class Solution {
public:
    vector<string> removeSubfolders(vector<string>& folder) {
        vector<string> result;
        for (string folderItem : folder) {
            if (folderItem[0] != '/') {
                result.push_back(folderItem);
            }
        }
        return result;
    }
};
